package NetMRI::SDN::Cisco;

use strict;
use warnings;
use Encode;
use Data::Dumper;
use NetMRI::SDN::Base;
use base 'NetMRI::SDN::Base';
use Date::Parse;
use NetMRI::Util::Date;
use NetMRI::Util::Network qw (netmaskFromPrefix InetAddr);

# Generated by SDN Agent POC - 2025-12-01 14:55:23

sub new {
    my $class = shift;
    my $self = $class->SUPER::new(@_);
    $self->{SaveDevices_unique_fieldname} = 'Serial';
    $self->{vendor_name} = 'Cisco';
    return bless $self, $class;
}

sub obtainEverything {
    my $self = shift;
    my $dev_role = $self->getDeviceRole();
    
    # Collect all data types
    $self->obtainSystemInfo();
    $self->obtainSdnFabricInterface();
    $self->obtainCdpLldp();
    $self->obtainSwitchPort();
    $self->obtainRoute();
    $self->obtainWireless();
}

sub getDevices {
    my $self = shift;
    
    $self->{logger}->debug("getDevices started");
    my $api_helper = $self->getApiClient();
    
    # Get organizations
    my ($organizations, $msg) = $api_helper->get_organizations();
    unless (defined $organizations) {
        $self->{logger}->warn('get_organizations failed: ' . $msg);
        return [];
    }
    
    my @devices;
    
    # Get devices from each organization
    foreach my $org (@$organizations) {
        my ($org_devices, $error) = $api_helper->get_organization_devices($org->{id});
        next if $error;
        
        foreach my $dev (@$org_devices) {
            my %device = (
                SdnControllerId => $api_helper->{fabric_id},
                SdnDeviceDN => "$org->{id}/$dev->{networkId}/$dev->{serial}",
                Name => $dev->{name} || $dev->{serial},
                Serial => $dev->{serial},
                Model => $dev->{model},
                Vendor => $self->{vendor_name},
                SWVersion => $dev->{firmware} || '',
                IPAddress => $dev->{lanIp} || $dev->{wan1Ip} || $dev->{publicIp},
                MACAddress => $dev->{mac} || '',
                modTS => NetMRI::Util::Date::formatDate(str2time($dev->{claimedAt}) || time()),
            );
            
            push @devices, \%device if $device{IPAddress};
        }
    }
    
    $self->{logger}->debug("Found " . scalar(@devices) . " devices");
    return \@devices;
}

sub obtainSdnFabricInterface {
    my $self = shift;
    
    $self->{logger}->debug("obtainSdnFabricInterface started");
    my $api_helper = $self->getApiClient();
    my $dn = $self->getDeviceDN();
    my ($org_id, $network_id, $serial) = split('/', $dn);
    
    my ($ports, $error) = $api_helper->get_device_switch_ports($serial);
    return unless $ports;
    
    my @interfaces;
    foreach my $port (@$ports) {
        my %interface = (
            SdnDeviceDN => $dn,
            ifIndex => $port->{portId} || '',
            ifName => $port->{name} || "Port $port->{portId}",
            ifOperStatus => $port->{status} || 'unknown',
            ifAdminStatus => $port->{enabled} ? 'up' : 'down',
            ifSpeed => $port->{speed} || '',
            ifDuplex => $port->{duplex} || '',
            ifType => $port->{type} || '',
            VlanIndex => $port->{vlan} || 0,
        );
        
        push @interfaces, \%interface;
    }
    
    $self->saveSdnFabricInterface(\@interfaces) if @interfaces;
}

sub obtainCdpLldp {
    my $self = shift;
    
    $self->{logger}->debug("obtainCdpLldp started");
    my $api_helper = $self->getApiClient();
    my $dn = $self->getDeviceDN();
    my ($org_id, $network_id, $serial) = split('/', $dn);
    
    my ($lldp_cdp, $error) = $api_helper->get_device_lldp_cdp($serial, {timespan => 7200});
    return unless $lldp_cdp;
    
    my @neighbors;
    my $ports = $lldp_cdp->{ports} || {};
    
    foreach my $port_id (keys %$ports) {
        my $port_data = $ports->{$port_id};
        
        # Process LLDP
        if ($port_data->{lldp}) {
            my $lldp = $port_data->{lldp};
            my %neighbor = (
                SdnDeviceDN => $dn,
                ifIndex => $port_id,
                NeighborDeviceID => $lldp->{systemName} || '',
                NeighborPortID => $lldp->{portId} || '',
                NeighborIPAddress => $lldp->{managementAddress} || '',
                Protocol => 'LLDP',
            );
            push @neighbors, \%neighbor;
        }
        
        # Process CDP
        if ($port_data->{cdp}) {
            my $cdp = $port_data->{cdp};
            my %neighbor = (
                SdnDeviceDN => $dn,
                ifIndex => $port_id,
                NeighborDeviceID => $cdp->{deviceId} || '',
                NeighborPortID => $cdp->{portId} || '',
                NeighborIPAddress => $cdp->{address} || '',
                Protocol => 'CDP',
            );
            push @neighbors, \%neighbor;
        }
    }
    
    $self->saveSdnLldp(\@neighbors) if @neighbors;
}

sub obtainRoute {
    my $self = shift;
    
    $self->{logger}->debug("obtainRoute started");
    my $api_helper = $self->getApiClient();
    my $dn = $self->getDeviceDN();
    my ($org_id, $network_id, $serial) = split('/', $dn);
    
    my ($routes, $error) = $api_helper->get_network_appliance_static_routes($network_id);
    return unless $routes;
    
    my @static_routes;
    foreach my $route (@$routes) {
        my %route_info = (
            SdnDeviceDN => $dn,
            RouteCIDR => $route->{subnet} || '',
            RouteNextHop => $route->{gatewayIp} || '',
            RouteName => $route->{name} || '',
            RouteEnabled => $route->{enabled} ? 1 : 0,
        );
        
        push @static_routes, \%route_info;
    }
    
    $self->saveSdnRoute(\@static_routes) if @static_routes;
}

sub obtainWireless {
    my $self = shift;
    
    $self->{logger}->debug("obtainWireless started");
    my $api_helper = $self->getApiClient();
    my $dn = $self->getDeviceDN();
    my ($org_id, $network_id, $serial) = split('/', $dn);
    
    my ($ssids, $error) = $api_helper->get_network_wireless_ssids($network_id);
    return unless $ssids;
    
    my @wireless_ssids;
    foreach my $ssid (@$ssids) {
        my %ssid_info = (
            SdnDeviceDN => $dn,
            SSID => $ssid->{name} || '',
            SSIDEnabled => $ssid->{enabled} ? 1 : 0,
            SSIDNumber => $ssid->{number} || 0,
            AuthMode => $ssid->{authMode} || '',
            EncryptionMode => $ssid->{encryptionMode} || '',
        );
        
        push @wireless_ssids, \%ssid_info;
    }
    
    $self->saveSdnWirelessSsid(\@wireless_ssids) if @wireless_ssids;
}


1;
